Bash(node --experimental-strip-types -e "
import ts from 'typescript';
import * as fs from 'node:fs';
import * as path from 'node:path';

const inputDir = path.resolve\('src/core'\);
const source = fs.readFileSync\(path.join\(inputDir, 'util.ts'\), 'utf8'\);

const compilerOptions = {
  target: ts.ScriptTarget.ES2020,
  module: ts.ModuleKind.ESNext,
  declaration: true,
  sourceMap: false,
  removeComments: false,
  esModuleInterop: true,
  moduleResolution: ts.ModuleResolutionKind.Node10,
  noResolve: false,
  skipLibCheck: true,
  skipDefaultLibCheck: true,
};

// Simulating the transpiler's custom host - only resolves relative imports
const sources = new Map\(\);
// Add util.ts and type-util.ts
const tsFiles = fs.readdirSync\(inputDir\).filter\(f => f.endsWith\('.ts'\)\).map\(f => path.join\(inputDir, f\)\);
for \(const f of tsFiles\) {
  sources.set\(f, fs.readFileSync\(f, 'utf8'\)\);
}

const host = {
  getSourceFile: \(fileName, languageVersion\) => {
    if \(sources.has\(fileName\)\) {
      return ts.createSourceFile\(fileName, sources.get\(fileName\), languageVersion, true\);
    }
    return undefined;
  },
  getDefaultLibFileName: \(\) => 'lib.d.ts',
  writeFile: \(\) => {},
  getCurrentDirectory: \(\) => inputDir,
  getDirectories: \(\) => [],
  fileExists: \(fileName\) => sources.has\(fileName\),
  readFile: \(fileName\) => sources.get\(fileName\),
  getCanonicalFileName: \(fileName\) => fileName,
  useCaseSensitiveFileNames: \(\) => true,
  getNewLine: \(\) => '\\n',
  resolveModuleNames: \(moduleNames, containingFile\) => {
    return moduleNames.map\(\(moduleName\) => {
      if \(moduleName.startsWith\('./'\) || moduleName.startsWith\('../'\)\) {
        const resolved = path.join\(path.dirname\(containingFile\), moduleName\);
        if \(sources.has\(resolved\)\) {
          return { resolvedFileName: resolved };
        }
      }
      return undefined;
    }\);
  },
};

const outputs = new Map\(\);
const writeFile = \(fileName, data\) => {
  outputs.set\(fileName, data\);
};

const utilFile = path.join\(inputDir, 'util.ts'\);
const program = ts.createProgram\([utilFile], compilerOptions, host\);
const emitResult = program.emit\(undefined, writeFile, undefined, undefined, undefined\);

console.log\('Emit skipped:', emitResult.emitSkipped\);
console.log\('Emit diagnostics:', emitResult.diagnostics.length\);
for \(const d of emitResult.diagnostics\) {
  console.log\('  -', ts.flattenDiagnosticMessageText\(d.messageText, '\\n'\)\);
}

const utilJs = outputs.get\(path.join\(inputDir, 'util.js'\)\);
if \(utilJs\) {
  const hasMapConstKeysToEntries = utilJs.includes\('mapConstKeysToEntries'\);
  console.log\('Has mapConstKeysToEntries:', hasMapConstKeysToEntries\);

  if \(!hasMapConstKeysToEntries\) {
    console.log\('\\nLast 20 lines of util.js:'\);
    const lines = utilJs.split\('\\n'\);
    console.log\(lines.slice\(-20\).join\('\\n'\)\);
  }
} else {
  console.log\('util.js not generated!'\);
  console.log\('Generated files:', [...outputs.keys\(\)]\);
}
" 2>&1)
